<template>
    <div>
        <loader :is-visible="isLoading"></loader>
        <section class="main-content">
            <div id="divMaindealData" v-cloak>
                <div class="row">
                    <div class="col-md-12 padding-t_8">
                        <div class="theme-primary partition-full">
                            <span class="p-name text-white">{{ $t('ManageDeal') }}</span>
                        </div>
                    </div>
                </div>
                <div class="border p-3">
                    <Form ref="DealForm">
                        <dynamic-form ref="ManageDealForm" :buttons="buttons" :schema="FormSchema"
                            v-on:OnSubmit="saveForm"></dynamic-form>
                    </Form>
                    <modaladdindustry v-if="showaddindustryModal" callFrom="deal" @close="showaddindustryModal = false"
                        @updatedata="UpdateSelectJson"></modaladdindustry>
                    <modaladdroletitle v-if="showaddroletitleModal" callFrom="deal" @close="showaddroletitleModal = false"
                        @updatedata="UpdateSelectJson"></modaladdroletitle>
                    <modaladdleadsource v-if="showaddleadsourceModal" callFrom="deal"
                        @close="showaddleadsourceModal = false" @updatedata="UpdateSelectJson">
                    </modaladdleadsource>
                </div>
            </div>
        </section>
    </div>
</template>
<script>
import DataService from "../../../services/DataService";
import modaladdindustry from '../../../components/Common/Modal/modaladdindustry.vue'
import modaladdroletitle from '../../../components/Common/Modal/modaladdroletitle.vue'
import modaladdleadsource from '../../../components/Common/Modal/modaladdleadsource.vue'
export default {
    components: {
        modaladdindustry,
        modaladdroletitle,
        modaladdleadsource
    },
    data() {
        return {
            isLoading: false,
            dealId: this.$route.params.id,
            showaddindustryModal: false,
            showaddroletitleModal: false,
            showaddleadsourceModal: false,
            userid: null,
            companyId: null,
            username: null,
            dateFormat: null,
            FormSchema: [],
            buttons: [{
                type: "submit",
                class: "btn btn-success",
                text: "<i class='fa fa-save pr-2'></i>Save",
                onclick: this.saveForm
            },
            {
                type: "button",
                class: "btn btn-danger",
                text: "<i class='fa fa-close pr-2'></i>Cancel",
                onClick: this.onCancel,
                isVisible: true,
            },
            ],
        }
    },
    created: function () {
        var vm = this;
        this.userid = this.GetUserInfo.ID;
        this.companyId = this.GetUserInfo.CompanyId;
        this.username = this.GetUserInfo.Name;
        this.dateFormat = this.GetUserInfo.DateFormat;
        this.getForm(vm.dealId);
    },
    methods: {
        getForm: function (id) {
            var ths = this;
            ths.isLoading = true;
            var url = `recordId=${id}&moduleName=CRM&subModuleCode=CRM_DEALS&langCode=en`;
            DataService.GetDynamicForm(url).then(function (response) {                
                if (response != null && response.data != null) {
                    ths.FormSchema = ths.$refs.ManageDealForm.ConvertCustomFieldIntoDynamicFormObj(response.data.data);
                    ths.FormSchema.forEach((group, gi) => {
                        group.Data.forEach(async (field, fi) => {
                            if (field.name == 'industry_type_id') {
                                field.config.showAddIcon = true;
                                field.config.onAddButtonClick = ths.openaddIndustrypopup;
                            }
                            if (field.name == "lead_source_id") {
                                field.config.showAddIcon = true;
                                field.config.onAddButtonClick = ths.openaddLeadSourcepopup;
                            }
                            if (field.name == "role_title_id") {
                                field.config.showAddIcon = true;
                                field.config.onAddButtonClick = ths.openaddRoleTitlepopup;
                            }
                            if (field.name == 'deal_state' && field.value == '') {
                                field.config.options = null;
                            }
                            if (field.name == "deal_id") {
                                field.value = ths.dealId;
                            }
                            if (field.name == "deal_owner_id") {                                
                                if (field.value == '') {
                                    field.value = { label: ths.username, value: ths.userid }
                                }
                                else {
                                    if (field.config.options != null) {
                                        var obj = field.config.options.filter(x => x.value == field.value)[0];
                                        field.value = { label: obj.name, value: obj.value }
                                    } else {
                                        field.value = { label: ths.username, value: ths.userid }
                                    }
                                }
                                field.config.onSearchChange = ths.onSearchh;
                                ths.onSearchh(null,field," ");
                            }
                            if (field.name == 'status_id' && field.value == '') {
                                field.value = field.config.options.filter(x => x.name.toLowerCase() == 'active')[0].value;                               
                            }
                            if (field.name == 'deal_country' && field.value != '') {
                                var stateObj = group.Data.filter(x => x.name == 'deal_state')[0];
                                await ths.GetDropDownData('ACCOUNT_STATE', stateObj, field.value, 'EDIT');
                            }
                            if (field.name == 'closing_date' && field.value == '') {
                                field.value = new Date();
                                field.config = { mode: 'date', format: "M/D/YYYY" }
                            }
                            field.config.onChange = ths.onChangeEventForFields;
                        });
                    });
                    ths.isLoading = false;
                }
            });
        },
        onSearchh: function (e, selctedValue, search) {            
            var vm = this;
            vm.searchSelectDataa(search, vm, selctedValue);
        },
        searchSelectDataa: function (search, ths, selctedValue) {
            this.ShowSearchDataa(search, ths, selctedValue);
        },
        ShowSearchDataa: async function (search, ths, selctedValue) {            
            var vm = this;
            var appendingUrl = `id=&&moduleName=CRM&type=CRM_USERS&search=${search}&refId=`;
            selctedValue.config.options = [];
            if (typeof (selctedValue) == 'undefined') {
                selctedValue = 0;
            }
            await DataService.getDDLData(appendingUrl).then(function (response) {
                if (response.data) {
                    vm.JsonObj = response.data;
                    if (vm.JsonObj != null) {
                        response.data.DATA.forEach((item) => {
                            var obj = {
                                value: item.value,
                                name: item.name
                            }
                            selctedValue.config.options.push(obj);
                        })
                        vm.$refs.ManageDealForm.UpdateKeyValue();
                    }
                }
            });
        },
        onChangeEventForFields: function (x, y, z) {
            let ths = this;
            var vm = this;
            if (y.name == "deal_country") {
                ths.FormSchema.forEach((group, gi) => {
                    group.Data.forEach(async (field, fi) => {
                        if (field.name == "deal_state") {
                            let id = y.value;
                            await vm.GetDropDownData('ACCOUNT_STATE', field, id, null);
                        }
                    })
                })
            }
        },
        GetDropDownData: async function (type, field, id, action) {
            var vm = this;
            var url = `id=&moduleName=CRM&type=${type}&refId=${id}`;
            await DataService.getDDLData(url + "&search=").then(response => {
                if (response.data.DATA != undefined) {
                    var options = response.data.DATA;
                    field.config.options = [];
                    if (action != 'EDIT') {
                        field.value = '';
                    }
                    if (type == 'ACCOUNT_STATE') {
                        options.forEach((item) => {
                            field.config.options.push({
                                value: item.value,
                                name: item.name
                            })
                        })
                    }
                    vm.$refs.ManageDealForm.UpdateKeyValue();
                }
            });
        },
        openaddIndustrypopup: function () {
            var vm = this;
            vm.showaddindustryModal = true;
        },
        openaddRoleTitlepopup: function (item) {
            this.RoleTitleItemObject = item;
            this.showaddroletitleModal = true;
        },
        openaddLeadSourcepopup: function (item) {
            this.LeadSourceItemObject = item;
            this.showaddleadsourceModal = true;
        },
        UpdateSelectJson: function (name, json) {
            let ths = this;
            ths.FormSchema.forEach((group, gi) => {
                group.Data.forEach((field, fi) => {
                    if (field.name == name) {
                        if (json != null) {
                            field.config.options = [];
                            json.forEach(x => {
                                field.config.options.push({ name: x.name, value: x.value });
                            })
                        }
                    }
                })
            })
            ths.$refs.ManageDealForm.UpdateKeyValue();
        },
        saveForm() {
            var ths = this;
            ths.$refs.DealForm.validate().then(result => {
                if (result) {
                    ths.isLoading = true;
                    var CustomFieldArray = ths.$refs.ManageDealForm.ConvertDynamicFormObjToCustomFieldObj(ths.FormSchema);
                    CustomFieldArray.forEach((x) => {
                        if (x.field_name == "account_id") {
                            if (!ths.isBlank(x.field_value)) {
                                x.field_value = x.field_value.value;
                            }
                        }
                        if (x.field_name == "deal_owner_id") {
                            if (!ths.isBlank(x.field_value)) {
                                x.field_value = x.field_value.value;
                            }
                        }
                    })
                    var obj = {
                        data: CustomFieldArray,
                        moduleCode: "CRM",
                        subModuleCode: "CRM_DEALS"
                    }
                    DataService.SaveDynamicForm(JSON.stringify(obj)).then(function (response) {
                        if (response != null && response.data != null && response.data[0].Status == "Success") {
                            if (ths.dealId > 0) {
                                ths.ShowAlert(ths.$t('UpdatedSuccess', [ths.$t('Deal')]), "success", true, ths.$t("Alert"));
                                ths.$router.push({ name: 'CRMDeal' });
                            }
                            else {
                                ths.ShowAlert(ths.$t('AddedSuccess', [ths.$t('Deal')]), "success", true, ths.$t("Alert"));
                                ths.$router.push({ name: 'CRMDeal' });
                            }
                        }
                    })
                    ths.isLoading = false;
                }
            })
        },
        onCancel: function () {
            var vm = this;
            vm.$router.push({ name: 'CRMDeal' });

        },
    }
}
</script>